346	        for (int sr : {10, 15, 20, 25}) {
347	            for (int la : {8, 10, 12, 15, 20, 25}) {
348	                if (elapsed_seconds() > 0.15) goto done_greedy;
349	                std::vector<int> plan;
350	                std::vector<bool> sf;
351	                std::vector<int> sd;
352	                generate_greedy_plan(plan, sf, sd, la, sr);
353	                long long e = simulate(plan, sf, sd, sr);
354	                if (e < best_energy) {
355	                    best_energy = e;
356	                    best_plan = plan;
357	                    best_sf = sf;
358	                    best_sd = sd;
359	                    best_split_range = sr;
360	                }
361	            }
362	        }
363	        done_greedy:
