371	        double T_init = 20.0;
372	        double T_final = 0.01;
373	        double sa_start = elapsed_seconds();
374	        double sa_end = TIME_LIMIT - 0.05;
375	        double sa_budget = sa_end - sa_start;
376	
377	        while (elapsed_seconds() < sa_end) {
378	            double progress = (elapsed_seconds() - sa_start) / sa_budget;
379	            if (progress > 1.0) break;
380	            double T = T_init * std::pow(T_final / T_init, progress);
