382	            std::vector<int> new_plan = cur_plan;
383	            std::vector<bool> new_sf = cur_sf;
384	            std::vector<int> new_sd = cur_sd;
385	
386	            int op = RGen.an_int(0, 99);
387	            if (op < 35) {
388	                int idx = RGen.an_int(0, N_CONST - 1);
389	                new_plan[idx] = RGen.an_int(0, M_CONST - 1);
390	            } else if (op < 60) {
391	                int idx = RGen.an_int(0, N_CONST - 1);
392	                int len = RGen.an_int(2, std::min(14, N_CONST - idx));
393	                for (int i = 0; i < len; i++)
394	                    new_plan[idx + i] = RGen.an_int(0, M_CONST - 1);
395	            } else if (op < 75) {
396	                int idx = RGen.an_int(0, N_CONST - 1);
397	                new_sf[idx] = !new_sf[idx];
398	                if (new_sf[idx]) new_sd[idx] = RGen.an_int(0, M_CONST - 1);
399	            } else if (op < 88) {
400	                int idx = RGen.an_int(0, N_CONST - 1);
401	                new_sd[idx] = RGen.an_int(0, M_CONST - 1);
402	                new_sf[idx] = true;
403	            } else {
404	                int idx = RGen.an_int(0, N_CONST - 1);
405	                new_plan[idx] = RGen.an_int(0, M_CONST - 1);
406	                new_sf[idx] = (RGen.an_int(0, 1) == 1);
407	                if (new_sf[idx]) new_sd[idx] = RGen.an_int(0, M_CONST - 1);
408	            }
409	
410	            long long new_e = simulate(new_plan, new_sf, new_sd, best_split_range);
411	
412	            if (new_e < cur_energy) {
413	                cur_energy = new_e;
414	                cur_plan = new_plan;
415	                cur_sf = new_sf;
416	                cur_sd = new_sd;
417	                if (new_e < best_energy) {
418	                    best_energy = new_e;
419	                    best_plan = new_plan;
420	                    best_sf = new_sf;
421	                    best_sd = new_sd;
422	                }
423	            } else {
424	                double delta = (double)(new_e - cur_energy);
425	                if (RGen.a_double(0.0, 1.0) < std::exp(-delta / T)) {
426	                    cur_energy = new_e;
427	                    cur_plan = new_plan;
428	                    cur_sf = new_sf;
429	                    cur_sd = new_sd;
430	                }
431	            }
432	        }
433	
434	        output(best_plan, best_sf, best_sd, best_split_range);
435	    }
