auto GLOBAL_START_TIME = std::chrono::steady_clock::now();

double elapsed_seconds() {
    return std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
}

struct RandomGenerator {
    std::mt19937 rng;
    RandomGenerator() : rng(std::chrono::steady_clock::now().time_since_epoch().count()) {}
    int an_int(int lo, int hi) {
        if (lo > hi) return lo;
        return std::uniform_int_distribution<int>(lo, hi)(rng);
    }
    double a_double(double lo, double hi) {
        return std::uniform_real_distribution<double>(lo, hi)(rng);
    }
} RGen;

const double TIME_LIMIT = 1.95;
const int N_CONST = 200;
const int M_CONST = 10;
const int H_CONST = 20;

struct State {
    std::vector<int> stacks[M_CONST];
    int box_stack[N_CONST];
    int box_height[N_CONST];
    long long energy;
    int next_target;
    int op_count;

    void init(const std::vector<std::vector<int>>& initial) {
        energy = 0;
        next_target = 0;
        op_count = 0;
        for (int i = 0; i < M_CONST; i++) {
            stacks[i] = initial[i];
            for (int j = 0; j < (int)stacks[i].size(); j++) {
                box_stack[stacks[i][j]] = i;
                box_height[stacks[i][j]] = j;
            }
        }
    }

    void move_block(int box_val, int dest) {
        int src = box_stack[box_val];
        int h = box_height[box_val];
        int num_moved = (int)stacks[src].size() - h;
        int old_dest_h = (int)stacks[dest].size();

        for (int i = h; i < h + num_moved; i++) {
            int bv = stacks[src][i];
            box_stack[bv] = dest;
            box_height[bv] = old_dest_h + (i - h);
            stacks[dest].push_back(bv);
        }
        stacks[src].resize(h);
        energy += (num_moved + 1);
        op_count++;
    }

    void carry_out() {
        int bv = next_target;
        int src = box_stack[bv];
        stacks[src].pop_back();
        next_target++;
        op_count++;
    }

    bool target_on_top() const {
        if (next_target >= N_CONST) return false;
        int src = box_stack[next_target];
        return (!stacks[src].empty() && stacks[src].back() == next_target);
    }
};

struct Solver {
    std::vector<std::vector<int>> initial;

    void read_input() {
        initial.resize(M_CONST);
        for (int i = 0; i < M_CONST; i++) {
            initial[i].resize(H_CONST);
            for (int j = 0; j < H_CONST; j++) {
                std::cin >> initial[i][j];
                initial[i][j]--;
            }
        }
    }

    int greedy_best_dest(const State& st, int target_k, int src, int lookahead) {
        int best_d = -1;
        double best_s = 1e18;
        for (int d = 0; d < M_CONST; d++) {
            if (d == src) continue;
            double s = 0;
            int dsz = (int)st.stacks[d].size();
            s += dsz * 0.5;
            if (dsz == 0) {
                s -= 8.0;
            } else {
                int check_from = std::max(0, dsz - 5);
                for (int i = dsz - 1; i >= check_from; i--) {
                    int bv = st.stacks[d][i];
                    if (bv > target_k && bv < target_k + lookahead) {
                        double urgency = (double)(lookahead - (bv - target_k)) / lookahead;
                        s += 8.0 * urgency;
                        if (i == dsz - 1) s += 12.0 * urgency;
                    }
                }
            }
            if (s < best_s) { best_s = s; best_d = d; }
        }
        return best_d;
    }

    // Run greedy simulation from current state to completion, return total energy
    long long greedy_rollout(State st, int lookahead) {
        while (st.next_target < N_CONST) {
            while (st.target_on_top()) st.carry_out();
            if (st.next_target >= N_CONST) break;

            int target_k = st.next_target;
            int src = st.box_stack[target_k];
            int h = st.box_height[target_k];
            int src_sz = (int)st.stacks[src].size();

            if (h == src_sz - 1) {
                st.carry_out();
                continue;
            }

            int first_above = st.stacks[src][h + 1];
            int pd = greedy_best_dest(st, target_k, src, lookahead);
            if (pd < 0 || pd == src) pd = (src + 1) % M_CONST;
            st.move_block(first_above, pd);
            st.carry_out();
            if (st.op_count > 5000) return (long long)1e15;
        }
        return st.energy;
    }

    // Generate candidate moves for clearing above target
    struct Candidate {
        // moves[i] = {box_to_move, destination}
        std::vector<std::pair<int,int>> moves;
    };

    void generate_candidates(const State& st, int target_k, std::vector<Candidate>& candidates) {
        int src = st.box_stack[target_k];
        int h = st.box_height[target_k];
        int src_sz = (int)st.stacks[src].size();
        int num_above = src_sz - h - 1;

        if (num_above <= 0) return;

        int first_above = st.stacks[src][h + 1];

        // Option 1: Move all above to each destination (9 options)
        for (int d = 0; d < M_CONST; d++) {
            if (d == src) continue;
            Candidate c;
            c.moves.push_back({first_above, d});
            candidates.push_back(c);
        }

        // Option 2: Split into two chunks at various split points
        if (num_above > 1) {
            // Find interesting split points (near-future boxes)
            std::vector<int> split_points;
            for (int i = h + 1; i < src_sz - 1; i++) {
                int bv = st.stacks[src][i];
                if (bv > target_k && bv < target_k + 30) {
                    split_points.push_back(i);
                }
            }
            // Also try splitting at midpoint
            if (num_above >= 4) {
                int mid = h + 1 + num_above / 2;
                bool already_there = false;
                for (int sp : split_points) if (sp == mid) { already_there = true; break; }
                if (!already_there) split_points.push_back(mid);
            }

            // Limit split points
            if (split_points.size() > 5) split_points.resize(5);

            for (int sp : split_points) {
                // Move upper portion (sp+1 to end) first, then lower portion (h+1 to sp)
                int upper_box = st.stacks[src][sp + 1];
                int lower_box = st.stacks[src][h + 1];

                // Try a few destination combinations
                // Get top-3 destinations for upper portion
                std::vector<int> upper_dests, lower_dests;
                for (int d = 0; d < M_CONST; d++) {
                    if (d == src) {
                        upper_dests.push_back(d); // placeholder, will skip
                        lower_dests.push_back(d);
                        continue;
                    }
                    upper_dests.push_back(d);
                    lower_dests.push_back(d);
                }

                // Score destinations for upper portion
                std::vector<std::pair<double,int>> upper_scores;
                for (int d = 0; d < M_CONST; d++) {
                    if (d == src) continue;
                    double s = (int)st.stacks[d].size() * 0.5;
                    if (st.stacks[d].empty()) s -= 8.0;
                    upper_scores.push_back({s, d});
                }
                std::sort(upper_scores.begin(), upper_scores.end());

                // Take top 3 destinations for upper
                int n_upper_d = std::min(3, (int)upper_scores.size());
                for (int ui = 0; ui < n_upper_d; ui++) {
                    int d1 = upper_scores[ui].second;
                    // For each upper dest, try top 3 destinations for lower
                    std::vector<std::pair<double,int>> lower_scores;
                    for (int d = 0; d < M_CONST; d++) {
                        if (d == src) continue;
                        double s = (int)st.stacks[d].size() * 0.5;
                        if (d == d1) s += (src_sz - sp - 1) * 0.5; // account for stuff just moved there
                        if (st.stacks[d].empty() && d != d1) s -= 8.0;
                        lower_scores.push_back({s, d});
                    }
                    std::sort(lower_scores.begin(), lower_scores.end());

                    int n_lower_d = std::min(3, (int)lower_scores.size());
                    for (int li = 0; li < n_lower_d; li++) {
                        int d2 = lower_scores[li].second;
                        Candidate c;
                        c.moves.push_back({upper_box, d1});
                        c.moves.push_back({lower_box, d2});
                        candidates.push_back(c);
                    }
                }
            }
        }

        // Limit total candidates
        if (candidates.size() > 60) candidates.resize(60);
    }

    // Apply candidate moves to state
    void apply_candidate(State& st, const Candidate& c) {
        for (auto& [box_val, dest] : c.moves) {
            int actual_src = st.box_stack[box_val];
            if (dest != actual_src) {
                st.move_block(box_val, dest);
            }
        }
    }

    struct Decision {
        int plan_dest; // primary destination for the block above target
