auto GLOBAL_START_TIME = std::chrono::steady_clock::now();

double elapsed_seconds() {
    return std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
}

struct RandomGenerator {
    std::mt19937 rng;
    RandomGenerator() : rng(std::chrono::steady_clock::now().time_since_epoch().count()) {}
    int an_int(int lo, int hi) {
        if (lo > hi) return lo;
        return std::uniform_int_distribution<int>(lo, hi)(rng);
    }
    double a_double(double lo, double hi) {
        return std::uniform_real_distribution<double>(lo, hi)(rng);
    }
} RGen;

const double TIME_LIMIT = 1.95;
const int N_CONST = 200;
const int M_CONST = 10;
const int H_CONST = 20;

struct State {
    std::vector<int> stacks[M_CONST];
    int box_stack[N_CONST];
    int box_height[N_CONST];
    long long energy;
    int next_target;
    int op_count;

    void init(const std::vector<std::vector<int>>& initial) {
        energy = 0;
        next_target = 0;
        op_count = 0;
        for (int i = 0; i < M_CONST; i++) {
            stacks[i] = initial[i];
            for (int j = 0; j < (int)stacks[i].size(); j++) {
                box_stack[stacks[i][j]] = i;
                box_height[stacks[i][j]] = j;
            }
        }
    }

    void move_block(int box_val, int dest) {
        int src = box_stack[box_val];
        int h = box_height[box_val];
        int num_moved = (int)stacks[src].size() - h;
        int old_dest_h = (int)stacks[dest].size();

        for (int i = h; i < h + num_moved; i++) {
            int bv = stacks[src][i];
            box_stack[bv] = dest;
            box_height[bv] = old_dest_h + (i - h);
            stacks[dest].push_back(bv);
        }
        stacks[src].resize(h);
        energy += (num_moved + 1);
        op_count++;
    }

    void carry_out() {
        int bv = next_target;
        int src = box_stack[bv];
        stacks[src].pop_back();
        next_target++;
        op_count++;
    }

    bool target_on_top() const {
        if (next_target >= N_CONST) return false;
        int src = box_stack[next_target];
        return (!stacks[src].empty() && stacks[src].back() == next_target);
    }
};

struct Solver {
    std::vector<std::vector<int>> initial;

    void read_input() {
        initial.resize(M_CONST);
        for (int i = 0; i < M_CONST; i++) {
            initial[i].resize(H_CONST);
            for (int j = 0; j < H_CONST; j++) {
                std::cin >> initial[i][j];
                initial[i][j]--;
            }
        }
    }

    int greedy_best_dest(const State& st, int target_k, int src, int lookahead) {
        int best_d = -1;
        double best_s = 1e18;
        for (int d = 0; d < M_CONST; d++) {
            if (d == src) continue;
            double s = 0;
            int dsz = (int)st.stacks[d].size();
            s += dsz * 0.5;
            if (dsz == 0) {
                s -= 8.0;
            } else {
                int check_from = std::max(0, dsz - 5);
                for (int i = dsz - 1; i >= check_from; i--) {
                    int bv = st.stacks[d][i];
                    if (bv > target_k && bv < target_k + lookahead) {
                        double urgency = (double)(lookahead - (bv - target_k)) / lookahead;
                        s += 8.0 * urgency;
                        if (i == dsz - 1) s += 12.0 * urgency;
                    }
                }
            }
            if (s < best_s) { best_s = s; best_d = d; }
        }
        return best_d;
    }

    // Evaluate state quality heuristically (lower is better)
    double eval_state(const State& st) {
        double score = st.energy;
        int target = st.next_target;

        // Estimate remaining cost based on how buried future targets are
        for (int k = target; k < std::min(target + 30, N_CONST); k++) {
            int s = st.box_stack[k];
            int h = st.box_height[k];
            int sz = (int)st.stacks[s].size();
            int above = sz - h - 1;
            if (above > 0) {
                double weight = 1.0 / (1.0 + (k - target) * 0.15);
                score += above * 2.0 * weight;
            }
        }
        return score;
    }

    // Run greedy for a limited number of target extractions, return state evaluation
    double bounded_greedy_eval(State st, int max_targets, int lookahead) {
        int targets_done = 0;
        while (st.next_target < N_CONST && targets_done < max_targets) {
            while (st.target_on_top()) { st.carry_out(); targets_done++; }
            if (st.next_target >= N_CONST || targets_done >= max_targets) break;

            int target_k = st.next_target;
            int src = st.box_stack[target_k];
            int h = st.box_height[target_k];
            int src_sz = (int)st.stacks[src].size();

            if (h == src_sz - 1) {
                st.carry_out();
                targets_done++;
                continue;
            }

            int first_above = st.stacks[src][h + 1];
            int pd = greedy_best_dest(st, target_k, src, lookahead);
            if (pd < 0 || pd == src) pd = (src + 1) % M_CONST;
            st.move_block(first_above, pd);
            st.carry_out();
            targets_done++;
            if (st.op_count > 5000) return 1e15;
        }
        return eval_state(st);
    }

    // Full greedy rollout returning total energy
    long long greedy_rollout(State st, int lookahead) {
        while (st.next_target < N_CONST) {
            while (st.target_on_top()) st.carry_out();
            if (st.next_target >= N_CONST) break;

            int target_k = st.next_target;
            int src = st.box_stack[target_k];
            int h = st.box_height[target_k];
            int src_sz = (int)st.stacks[src].size();

            if (h == src_sz - 1) {
                st.carry_out();
                continue;
            }

            int first_above = st.stacks[src][h + 1];
            int pd = greedy_best_dest(st, target_k, src, lookahead);
            if (pd < 0 || pd == src) pd = (src + 1) % M_CONST;
            st.move_block(first_above, pd);
            st.carry_out();
            if (st.op_count > 5000) return (long long)1e15;
        }
        return st.energy;
    }

    // Beam search: maintain top-K states at each step
    struct BeamState {
        State st;
        double score;
        std::vector<std::pair<int,int>> history; // moves made (box, dest) - only the moves, not carry-outs
    };

    void solve() {
        const int LOOKAHEAD = 15;
        const int BEAM_WIDTH = 5;
        const int EVAL_DEPTH = 8; // greedy rollout depth for evaluation

        // Phase 1: Beam search
        std::vector<BeamState> beam;
        {
            BeamState init_bs;
            init_bs.st.init(initial);
            init_bs.score = 0;
            beam.push_back(init_bs);
        }

        double beam_time_limit = 1.0; // spend up to 1s on beam search

        while (!beam.empty() && elapsed_seconds() < beam_time_limit) {
            // Find state to expand (the one with lowest score among non-finished)
            // Actually, let's do step-by-step: advance all beam states one target step

            std::vector<BeamState> next_beam;

            for (auto& bs : beam) {
                // Advance to next target that needs a move
                while (bs.st.target_on_top()) bs.st.carry_out();
                if (bs.st.next_target >= N_CONST) {
                    // This state is done
                    next_beam.push_back(bs);
                    next_beam.back().score = bs.st.energy;
                    continue;
                }

                int target_k = bs.st.next_target;
                int src = bs.st.box_stack[target_k];
                int h = bs.st.box_height[target_k];
                int src_sz = (int)bs.st.stacks[src].size();

                if (h == src_sz - 1) {
                    // Target is on top, just carry out
                    BeamState nbs = bs;
                    nbs.st.carry_out();
                    nbs.score = eval_state(nbs.st);
                    next_beam.push_back(nbs);
                    continue;
                }

                // Generate candidate moves
                int first_above = bs.st.stacks[src][h + 1];
                int num_above = src_sz - h - 1;

                // Option A: Move all above to each destination
                for (int d = 0; d < M_CONST; d++) {
                    if (d == src) continue;
                    BeamState nbs = bs;
                    nbs.st.move_block(first_above, d);
                    nbs.history.push_back({first_above, d});
                    // Carry out target
                    nbs.st.carry_out();
                    nbs.score = bounded_greedy_eval(nbs.st, EVAL_DEPTH, LOOKAHEAD);
                    next_beam.push_back(nbs);
                }

                // Option B: Split moves (if beneficial)
                if (num_above > 1 && next_beam.size() < 200) {
                    // Find split point: a near-future box
                    for (int i = h + 1; i < src_sz - 1 && i < h + 6; i++) {
                        int bv = bs.st.stacks[src][i];
                        if (bv > target_k && bv < target_k + 20) {
                            // Split: move above i to best dest, then move h+1..i to another
                            int upper_box = bs.st.stacks[src][i + 1];

                            // Try 3 best destinations for upper portion
                            for (int d1 = 0; d1 < M_CONST; d1++) {
                                if (d1 == src) continue;
                                // Pick best d2 for lower portion
                                int d2 = greedy_best_dest(bs.st, target_k, src, LOOKAHEAD);
                                if (d2 < 0 || d2 == src) d2 = (src + 1) % M_CONST;

                                BeamState nbs = bs;
                                nbs.st.move_block(upper_box, d1);
                                nbs.history.push_back({upper_box, d1});

                                // Now move remaining above target
                                int new_src = nbs.st.box_stack[target_k];
                                int new_h = nbs.st.box_height[target_k];
                                if (new_h < (int)nbs.st.stacks[new_src].size() - 1) {
                                    int new_first = nbs.st.stacks[new_src][new_h + 1];
                                    if (d2 == new_src) d2 = (new_src + 1) % M_CONST;
                                    nbs.st.move_block(new_first, d2);
                                    nbs.history.push_back({new_first, d2});
                                }
                                nbs.st.carry_out();
                                nbs.score = bounded_greedy_eval(nbs.st, EVAL_DEPTH, LOOKAHEAD);
                                next_beam.push_back(nbs);
                            }
                            break; // only first split point
                        }
                    }
                }
            }

            // Keep top BEAM_WIDTH states
            if (next_beam.empty()) break;

            std::sort(next_beam.begin(), next_beam.end(),
                      [](const BeamState& a, const BeamState& b) { return a.score < b.score; });

            if ((int)next_beam.size() > BEAM_WIDTH)
                next_beam.resize(BEAM_WIDTH);

            beam = std::move(next_beam);

            // Check if all done
            bool all_done = true;
            for (auto& bs : beam) {
                if (bs.st.next_target < N_CONST) { all_done = false; break; }
            }
            if (all_done) break;
        }

        // Get best beam result
        long long beam_energy = (long long)1e18;
        int best_beam_idx = 0;
        for (int i = 0; i < (int)beam.size(); i++) {
            if (beam[i].st.next_target >= N_CONST && beam[i].st.energy < beam_energy) {
                beam_energy = beam[i].st.energy;
                best_beam_idx = i;
            }
        }

        // Phase 2: Also try greedy+SA approach as comparison
        std::vector<int> best_plan;
        std::vector<bool> best_sf;
        std::vector<int> best_sd;
        long long best_energy = (long long)1e18;
        int best_split_range = 15;

        for (int sr : {10, 15, 20, 25}) {
            for (int la : {8, 10, 12, 15, 20, 25}) {
                if (elapsed_seconds() > 1.2) goto done_greedy;
                std::vector<int> plan;
                std::vector<bool> sf;
                std::vector<int> sd;
                generate_greedy_plan(plan, sf, sd, la, sr);
                long long e = simulate(plan, sf, sd, sr);
                if (e < best_energy) {
                    best_energy = e;
                    best_plan = plan;
                    best_sf = sf;
                    best_sd = sd;
                    best_split_range = sr;
                }
            }
        }
        done_greedy:

        // SA phase
        std::vector<int> cur_plan = best_plan;
        std::vector<bool> cur_sf = best_sf;
        std::vector<int> cur_sd = best_sd;
        long long cur_energy = best_energy;

        double T_init = 20.0;
        double T_final = 0.01;
        double sa_start = elapsed_seconds();
        double sa_end = TIME_LIMIT - 0.05;
        double sa_budget = sa_end - sa_start;

        if (sa_budget > 0.1) {
            while (elapsed_seconds() < sa_end) {
                double progress = (elapsed_seconds() - sa_start) / sa_budget;
                if (progress > 1.0) break;
                double T = T_init * std::pow(T_final / T_init, progress);

                std::vector<int> new_plan = cur_plan;
                std::vector<bool> new_sf = cur_sf;
                std::vector<int> new_sd = cur_sd;

                int op = RGen.an_int(0, 99);
                if (op < 35) {
                    int idx = RGen.an_int(0, N_CONST - 1);
                    new_plan[idx] = RGen.an_int(0, M_CONST - 1);
                } else if (op < 60) {
                    int idx = RGen.an_int(0, N_CONST - 1);
                    int len = RGen.an_int(2, std::min(14, N_CONST - idx));
                    for (int i = 0; i < len; i++)
                        new_plan[idx + i] = RGen.an_int(0, M_CONST - 1);
                } else if (op < 75) {
                    int idx = RGen.an_int(0, N_CONST - 1);
                    new_sf[idx] = !new_sf[idx];
                    if (new_sf[idx]) new_sd[idx] = RGen.an_int(0, M_CONST - 1);
                } else if (op < 88) {
                    int idx = RGen.an_int(0, N_CONST - 1);
                    new_sd[idx] = RGen.an_int(0, M_CONST - 1);
                    new_sf[idx] = true;
                } else {
                    int idx = RGen.an_int(0, N_CONST - 1);
                    new_plan[idx] = RGen.an_int(0, M_CONST - 1);
                    new_sf[idx] = (RGen.an_int(0, 1) == 1);
                    if (new_sf[idx]) new_sd[idx] = RGen.an_int(0, M_CONST - 1);
                }

                long long new_e = simulate(new_plan, new_sf, new_sd, best_split_range);

                if (new_e < cur_energy) {
                    cur_energy = new_e;
                    cur_plan = new_plan;
                    cur_sf = new_sf;
                    cur_sd = new_sd;
                    if (new_e < best_energy) {
                        best_energy = new_e;
                        best_plan = new_plan;
                        best_sf = new_sf;
                        best_sd = new_sd;
                    }
                } else {
                    double delta = (double)(new_e - cur_energy);
                    if (RGen.a_double(0.0, 1.0) < std::exp(-delta / T)) {
                        cur_energy = new_e;
                        cur_plan = new_plan;
                        cur_sf = new_sf;
                        cur_sd = new_sd;
                    }
                }
            }
        }

        // Output the best of beam vs SA
        if (beam_energy < best_energy && beam_energy < (long long)1e15) {
            // Replay beam solution
            output_replay(beam[best_beam_idx].history);
        } else {
            output(best_plan, best_sf, best_sd, best_split_range);
        }
    }

    void output_replay(const std::vector<std::pair<int,int>>& history) {
        // We need to replay the beam search decisions
