                    best_plan = plan;
                    best_sf = sf;
                    best_sd = sd;
                    best_split_range = sr;
                }
            }
        }
        done_greedy:

        // Phase 2: Build checkpoints for delta evaluation
        build_checkpoints(best_plan, best_sf, best_sd, best_split_range);

        // Phase 3: SA with checkpoint-based delta evaluation
        std::vector<int> cur_plan = best_plan;
        std::vector<bool> cur_sf = best_sf;
        std::vector<int> cur_sd = best_sd;
        long long cur_energy = best_energy;

        double T_init = 20.0;
        double T_final = 0.01;
        double sa_start = elapsed_seconds();
        double sa_end = TIME_LIMIT - 0.05;
        double sa_budget = sa_end - sa_start;

        int iters = 0;
        int accepted = 0;
        int checkpoint_used = 0;

        while (elapsed_seconds() < sa_end) {
            double progress = (elapsed_seconds() - sa_start) / sa_budget;
            if (progress > 1.0) break;
            double T = T_init * std::pow(T_final / T_init, progress);

            std::vector<int> new_plan = cur_plan;
            std::vector<bool> new_sf = cur_sf;
            std::vector<int> new_sd = cur_sd;

            int min_changed_idx = N_CONST;
            int op = RGen.an_int(0, 99);
            if (op < 35) {
                int idx = RGen.an_int(0, N_CONST - 1);
                new_plan[idx] = RGen.an_int(0, M_CONST - 1);
                min_changed_idx = idx;
            } else if (op < 60) {
                int idx = RGen.an_int(0, N_CONST - 1);
                int len = RGen.an_int(2, std::min(14, N_CONST - idx));
                for (int i = 0; i < len; i++)
                    new_plan[idx + i] = RGen.an_int(0, M_CONST - 1);
                min_changed_idx = idx;
            } else if (op < 75) {
                int idx = RGen.an_int(0, N_CONST - 1);
                new_sf[idx] = !new_sf[idx];
                if (new_sf[idx]) new_sd[idx] = RGen.an_int(0, M_CONST - 1);
                min_changed_idx = idx;
            } else if (op < 88) {
                int idx = RGen.an_int(0, N_CONST - 1);
                new_sd[idx] = RGen.an_int(0, M_CONST - 1);
                new_sf[idx] = true;
                min_changed_idx = idx;
            } else {
                int idx = RGen.an_int(0, N_CONST - 1);
                new_plan[idx] = RGen.an_int(0, M_CONST - 1);
                new_sf[idx] = (RGen.an_int(0, 1) == 1);
                if (new_sf[idx]) new_sd[idx] = RGen.an_int(0, M_CONST - 1);
                min_changed_idx = idx;
            }

            // Find the nearest checkpoint before min_changed_idx
            long long new_e;
            int ckpt_idx = 0;
            for (int c = num_checkpoints - 1; c >= 0; c--) {
                if (checkpoint_targets[c] <= min_changed_idx) {
                    ckpt_idx = c;
                    break;
                }
            }

            // If nothing changed before checkpoint, use delta eval
            // But we can only use checkpoints from cur_plan, not new_plan
            // Checkpoints are only valid if plan hasn't changed before the checkpoint
            // So we can only use checkpoint if min_changed_idx >= checkpoint_targets[ckpt_idx]
            // AND new_plan == cur_plan for all indices < checkpoint_targets[ckpt_idx]
            // Since we only change indices >= min_changed_idx, and checkpoint is at <= min_changed_idx,
            // we need the plan to be identical before the checkpoint.
            // But we're comparing new_plan with cur_plan... new_plan differs from cur_plan only at >= min_changed_idx.
            // So if checkpoint_targets[ckpt_idx] <= min_changed_idx, the checkpoint is valid for new_plan too!

            if (ckpt_idx > 0 && checkpoint_targets[ckpt_idx] <= min_changed_idx) {
                new_e = simulate_from(checkpoint_targets[ckpt_idx], checkpoints[ckpt_idx],
                                      new_plan, new_sf, new_sd, best_split_range);
                checkpoint_used++;
            } else {
                new_e = simulate(new_plan, new_sf, new_sd, best_split_range);
            }

            iters++;

            if (new_e < cur_energy) {
                cur_energy = new_e;
                cur_plan = new_plan;
                cur_sf = new_sf;
                cur_sd = new_sd;
                accepted++;
                if (new_e < best_energy) {
                    best_energy = new_e;
                    best_plan = new_plan;
                    best_sf = new_sf;
                    best_sd = new_sd;
                    // Rebuild checkpoints for new best
                    build_checkpoints(best_plan, best_sf, best_sd, best_split_range);
                }
            } else {
                double delta = (double)(new_e - cur_energy);
                if (RGen.a_double(0.0, 1.0) < std::exp(-delta / T)) {
                    cur_energy = new_e;
                    cur_plan = new_plan;
                    cur_sf = new_sf;
                    cur_sd = new_sd;
                    accepted++;
                    // Rebuild checkpoints for current
                    if (iters % 200 == 0) {
                        build_checkpoints(cur_plan, cur_sf, cur_sd, best_split_range);
                    }
                }
            }
        }

        output(best_plan, best_sf, best_sd, best_split_range);
    }

