            long long new_e;
            int ckpt_idx = 0;
            for (int c = num_checkpoints - 1; c >= 0; c--) {
                if (checkpoint_targets[c] <= min_changed_idx) {
                    ckpt_idx = c;
                    break;
                }
            }

