            // But we can only use checkpoints from cur_plan, not new_plan
            // Checkpoints are only valid if plan hasn't changed before the checkpoint
            // So we can only use checkpoint if min_changed_idx >= checkpoint_targets[ckpt_idx]
            // AND new_plan == cur_plan for all indices < checkpoint_targets[ckpt_idx]
            // Since we only change indices >= min_changed_idx, and checkpoint is at <= min_changed_idx,
            // we need the plan to be identical before the checkpoint.
            // But we're comparing new_plan with cur_plan... new_plan differs from cur_plan only at >= min_changed_idx.
            // So if checkpoint_targets[ckpt_idx] <= min_changed_idx, the checkpoint is valid for new_plan too!

            if (ckpt_idx > 0 && checkpoint_targets[ckpt_idx] <= min_changed_idx) {
                new_e = simulate_from(checkpoint_targets[ckpt_idx], checkpoints[ckpt_idx],
                                      new_plan, new_sf, new_sd, best_split_range);
                checkpoint_used++;
            } else {
                new_e = simulate(new_plan, new_sf, new_sd, best_split_range);
            }

            iters++;

