                cur_energy = new_e;
                cur_plan = new_plan;
                cur_sf = new_sf;
                cur_sd = new_sd;
                accepted++;
                if (new_e < best_energy) {
                    best_energy = new_e;
                    best_plan = new_plan;
                    best_sf = new_sf;
                    best_sd = new_sd;
                    // Rebuild checkpoints for new best
                    build_checkpoints(best_plan, best_sf, best_sd, best_split_range);
                }
            } else {
                double delta = (double)(new_e - cur_energy);
                if (RGen.a_double(0.0, 1.0) < std::exp(-delta / T)) {
