        stacks[src].resize(h);
        energy += (num_moved + 1);
        op_count++;
    }

    void carry_out() {
        int bv = next_target;
        int src = box_stack[bv];
        stacks[src].pop_back();
        next_target++;
        op_count++;
    }

    bool target_on_top() const {
        if (next_target >= N_CONST) return false;
        int src = box_stack[next_target];
