# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <algorithm>
#include <chrono>
#include <random>
#include <cmath>
#include <utility>
#include <numeric>
#include <cstring>

auto GLOBAL_START_TIME = std::chrono::steady_clock::now();

double elapsed_seconds() {
    return std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
}

struct RandomGenerator {
    std::mt19937 rng;
    RandomGenerator() : rng(std::chrono::steady_clock::now().time_since_epoch().count()) {}
    int an_int(int lo, int hi) {
        if (lo > hi) return lo;
        return std::uniform_int_distribution<int>(lo, hi)(rng);
    }
    double a_double(double lo, double hi) {
        return std::uniform_real_distribution<double>(lo, hi)(rng);
    }
} RGen;

const double TIME_LIMIT = 1.95;
const int N_CONST = 200;
const int M_CONST = 10;
const int H_CONST = 20;
const int MAX_STACK_H = 220; // generous max height

// Fast state using fixed arrays - no allocations during simulation
struct FastState {
    int stacks[M_CONST][MAX_STACK_H];
    int stack_sz[M_CONST];
    int box_stack[N_CONST];
    int box_height[N_CONST];
    long long energy;
    int next_target;
    int op_count;

    void init(const int initial[M_CONST][H_CONST]) {
        energy = 0;
        next_target = 0;
        op_count = 0;
        for (int i = 0; i < M_CONST; i++) {
            stack_sz[i] = H_CONST;
            for (int j = 0; j < H_CONST; j++) {
                stacks[i][j] = initial[i][j];
                box_stack[initial[i][j]] = i;
                box_height[initial[i][j]] = j;
            }
        }
    }

    inline void move_block(int box_val, int dest) {
        int src = box_stack[box_val];
        int h = box_height[box_val];
        int num_moved = stack_sz[src] - h;
        int old_dest_h = stack_sz[dest];

        for (int i = 0; i < num_moved; i++) {
            int bv = stacks[src][h + i];
            stacks[dest][old_dest_h + i] = bv;
            box_stack[bv] = dest;
            box_height[bv] = old_dest_h + i;
        }
        stack_sz[src] = h;
        stack_sz[dest] = old_dest_h + num_moved;
        energy += (num_moved + 1);
        op_count++;
    }

    inline void carry_out() {
        int bv = next_target;
        int src = box_stack[bv];
        stack_sz[src]--;
        next_target++;
        op_count++;
    }

    inline bool target_on_top() const {
        if (next_target >= N_CONST) return false;
        int src = box_stack[next_target];
        return (stack_sz[src] > 0 && stacks[src][stack_sz[src] - 1] == next_target);
    }
};

struct Solver {
    int initial[M_CONST][H_CONST];

    void read_input() {
        for (int i = 0; i < M_CONST; i++) {
            for (int j = 0; j < H_CONST; j++) {
                std::cin >> initial[i][j];
                initial[i][j]--;
            }
        }
    }

    int greedy_best_dest(const FastState& st, int target_k, int src, int lookahead) {
        int best_d = -1;
        double best_s = 1e18;
        for (int d = 0; d < M_CONST; d++) {
            if (d == src) continue;
            double s = 0;
            int dsz = st.stack_sz[d];
            s += dsz * 0.5;
            if (dsz == 0) {
                s -= 8.0;
            } else {
                int check_from = std::max(0, dsz - 5);
                for (int i = dsz - 1; i >= check_from; i--) {
                    int bv = st.stacks[d][i];
                    if (bv > target_k && bv < target_k + lookahead) {
                        double urgency = (double)(lookahead - (bv - target_k)) / lookahead;
                        s += 8.0 * urgency;
                        if (i == dsz - 1) s += 12.0 * urgency;
                    }
                }
            }
            if (s < best_s) { best_s = s; best_d = d; }
        }
        return best_d;
    }

    long long simulate(const int* plan, const bool* split_flags,
                       const int* split_dests, int split_range) {
        FastState st;
        st.init(initial);

        while (st.next_target < N_CONST) {
            while (st.target_on_top()) st.carry_out();
            if (st.next_target >= N_CONST) break;

            int target_k = st.next_target;
            int src = st.box_stack[target_k];
            int h = st.box_height[target_k];
            int src_sz = st.stack_sz[src];

            if (h == src_sz - 1) {
                st.carry_out();
                continue;
            }

            int num_above = src_sz - h - 1;

            if (split_flags[target_k] && num_above > 1) {
                int split_box_idx = -1;
                for (int i = h + 1; i < src_sz - 1; i++) {
                    int bv = st.stacks[src][i];
                    if (bv > target_k && bv < target_k + split_range) {
                        split_box_idx = i;
                        break;
                    }
                }

                if (split_box_idx >= 0) {
                    int upper_start_box = st.stacks[src][split_box_idx + 1];
                    int sd = split_dests[target_k];
                    if (sd == src || sd < 0 || sd >= M_CONST) sd = (src + 1) % M_CONST;
                    st.move_block(upper_start_box, sd);

                    src = st.box_stack[target_k];
                    h = st.box_height[target_k];
                    if (h < st.stack_sz[src] - 1) {
                        int first_above = st.stacks[src][h + 1];
                        int pd = plan[target_k];
                        if (pd == src || pd < 0 || pd >= M_CONST) pd = (src + 1) % M_CONST;
                        st.move_block(first_above, pd);
                    }
                } else {
                    int first_above = st.stacks[src][h + 1];
                    int pd = plan[target_k];
                    if (pd == src || pd < 0 || pd >= M_CONST) pd = (src + 1) % M_CONST;
                    st.move_block(first_above, pd);
                }
            } else {
                int first_above = st.stacks[src][h + 1];
                int pd = plan[target_k];
                if (pd == src || pd < 0 || pd >= M_CONST) pd = (src + 1) % M_CONST;
                st.move_block(first_above, pd);
            }

            st.carry_out();
            if (st.op_count > 5000) return (long long)1e15;
        }

        if (st.op_count > 5000) return (long long)1e15;
        return st.energy;
    }

    void generate_greedy_plan(int* plan, bool* split_flags,
                              int* split_dests, int lookahead, int split_range) {
        memset(plan, 0, sizeof(int) * N_CONST);
        memset(split_flags, 0, sizeof(bool) * N_CONST);
        memset(split_dests, 0, sizeof(int) * N_CONST);

        FastState st;
        st.init(initial);

        while (st.next_target < N_CONST) {
            while (st.target_on_top()) st.carry_out();
            if (st.next_target >= N_CONST) break;

            int target_k = st.next_target;
            int src = st.box_stack[target_k];
            int h = st.box_height[target_k];
            int src_sz = st.stack_sz[src];

            if (h == src_sz - 1) {
                plan[target_k] = src;
                st.carry_out();
                continue;
            }

            int num_above = src_sz - h - 1;

            if (num_above > 1) {
                int split_box_idx = -1;
                for (int i = h + 1; i < src_sz - 1; i++) {
                    int bv = st.stacks[src][i];
                    if (bv > target_k && bv < target_k + split_range) {
                        split_box_idx = i;
                        break;
                    }
                }

                if (split_box_idx >= 0) {
                    split_flags[target_k] = true;
                    int upper_start_box = st.stacks[src][split_box_idx + 1];
                    int sd = greedy_best_dest(st, target_k, src, lookahead);
                    if (sd < 0 || sd == src) sd = (src + 1) % M_CONST;
                    split_dests[target_k] = sd;
                    st.move_block(upper_start_box, sd);

                    src = st.box_stack[target_k];
                    h = st.box_height[target_k];
                    if (h < st.stack_sz[src] - 1) {
                        int pd = greedy_best_dest(st, target_k, src, lookahead);
                        if (pd < 0 || pd == src) pd = (src + 1) % M_CONST;
                        plan[target_k] = pd;
                        int first_above = st.stacks[src][h + 1];
                        st.move_block(first_above, pd);
                    } else {
                        plan[target_k] = src;
                    }
                } else {
                    int pd = greedy_best_dest(st, target_k, src, lookahead);
                    if (pd < 0 || pd == src) pd = (src + 1) % M_CONST;
                    plan[target_k] = pd;
                    int first_above = st.stacks[src][h + 1];
                    st.move_block(first_above, pd);
                }
            } else {
                int pd = greedy_best_dest(st, target_k, src, lookahead);
                if (pd < 0 || pd == src) pd = (src + 1) % M_CONST;
                plan[target_k] = pd;
                int first_above = st.stacks[src][h + 1];
                st.move_block(first_above, pd);
            }

            st.carry_out();
        }
    }

    void solve() {
        int best_plan[N_CONST], cur_plan[N_CONST], new_plan[N_CONST];
        bool best_sf[N_CONST], cur_sf[N_CONST], new_sf[N_CONST];
        int best_sd[N_CONST], cur_sd[N_CONST], new_sd[N_CONST];
        long long best_energy = (long long)1e18;
        int best_split_range = 15;

        // Phase 1: Try greedy with different configs
        int tmp_plan[N_CONST];
        bool tmp_sf[N_CONST];
        int tmp_sd[N_CONST];

        for (int sr : {10, 15, 20, 25}) {
            for (int la : {8, 10, 12, 15, 20, 25}) {
                if (elapsed_seconds() > 0.15) goto done_greedy;
                generate_greedy_plan(tmp_plan, tmp_sf, tmp_sd, la, sr);
                long long e = simulate(tmp_plan, tmp_sf, tmp_sd, sr);
                if (e < best_energy) {
                    best_energy = e;
                    memcpy(best_plan, tmp_plan, sizeof(best_plan));
                    memcpy(best_sf, tmp_sf, sizeof(best_sf));
                    memcpy(best_sd, tmp_sd, sizeof(best_sd));
                    best_split_range = sr;
                }
            }
        }
        done_greedy:

        memcpy(cur_plan, best_plan, sizeof(cur_plan));
        memcpy(cur_sf, best_sf, sizeof(cur_sf));
        memcpy(cur_sd, best_sd, sizeof(cur_sd));
        long long cur_energy = best_energy;

        // SA phase
        double T_init = 20.0;
        double T_final = 0.01;
        double sa_start = elapsed_seconds();
        double sa_end = TIME_LIMIT - 0.05;
        double sa_budget = sa_end - sa_start;

        while (elapsed_seconds() < sa_end) {
            double progress = (elapsed_seconds() - sa_start) / sa_budget;
            if (progress > 1.0) break;
            double T = T_init * std::pow(T_final / T_init, progress);

            memcpy(new_plan, cur_plan, sizeof(new_plan));
            memcpy(new_sf, cur_sf, sizeof(new_sf));
            memcpy(new_sd, cur_sd, sizeof(new_sd));

            int op = RGen.an_int(0, 99);
            if (op < 35) {
                int idx = RGen.an_int(0, N_CONST - 1);
                new_plan[idx] = RGen.an_int(0, M_CONST - 1);
            } else if (op < 60) {
                int idx = RGen.an_int(0, N_CONST - 1);
                int len = RGen.an_int(2, std::min(14, N_CONST - idx));
                for (int i = 0; i < len; i++)
                    new_plan[idx + i] = RGen.an_int(0, M_CONST - 1);
            } else if (op < 75) {
                int idx = RGen.an_int(0, N_CONST - 1);
                new_sf[idx] = !new_sf[idx];
                if (new_sf[idx]) new_sd[idx] = RGen.an_int(0, M_CONST - 1);
            } else if (op < 88) {
                int idx = RGen.an_int(0, N_CONST - 1);
                new_sd[idx] = RGen.an_int(0, M_CONST - 1);
                new_sf[idx] = true;
            } else {
                int idx = RGen.an_int(0, N_CONST - 1);
                new_plan[idx] = RGen.an_int(0, M_CONST - 1);
                new_sf[idx] = (RGen.an_int(0, 1) == 1);
